```rust
fn _bostree_rotate_right(tree: &mut BOSTree, p: &Rc<RefCell<BOSNode>>) -> Rc<RefCell<BOSNode>> {
    // Read all values we need before modifying anything
    let p_parent = p.borrow().parent_node.clone();
    let l = p.borrow().left_child_node.clone().unwrap();
    let l_right = l.borrow().right_child_node.clone();
    let l_right_count = l.borrow().right_child_count;

    // Determine if P is left or right child of its parent
    let p_is_left_child = if let Some(ref p_parent_weak) = p_parent {
        if let Some(p_parent_rc) = p_parent_weak.upgrade() {
            p_parent_rc.borrow().left_child_node.as_ref().map_or(false, |left| Rc::ptr_eq(left, p))
        } else {
            false
        }
    } else {
        false
    };

    // Modify P's parent's child pointer
    if let Some(ref p_parent_weak) = p_parent {
        if let Some(p_parent_rc) = p_parent_weak.upgrade() {
            if p_is_left_child {
                p_parent_rc.borrow_mut().left_child_node = Some(l.clone());
            } else {
                p_parent_rc.borrow_mut().right_child_node = Some(l.clone());
            }
        }
    } else {
        tree.root_node = Some(l.clone());
    }

    // Set L's parent
    l.borrow_mut().parent_node = p_parent;

    // Set P's left child to L's right child
    p.borrow_mut().left_child_node = l_right.clone();
    p.borrow_mut().left_child_count = l_right_count;

    // If P's new left child exists, set its parent to P
    if let Some(ref l_right_node) = l_right {
        l_right_node.borrow_mut().parent_node = Some(Rc::downgrade(p));
    }

    // Update P's depth
    {
        let p_borrow = p.borrow();
        let left_depth = p_borrow.left_child_node.as_ref().map_or(0, |n| n.borrow().depth + 1);
        let right_depth = p_borrow.right_child_node.as_ref().map_or(0, |n| n.borrow().depth + 1);
        p.borrow_mut().depth = left_depth.max(right_depth);
    }

    // Set P's parent to L
    p.borrow_mut().parent_node = Some(Rc::downgrade(&l));

    // Set L's right child to P
    l.borrow_mut().right_child_node = Some(p.clone());

    // Update L's right_child_count and depth
    {
        let p_borrow = p.borrow();
        l.borrow_mut().right_child_count = p_borrow.left_child_count + p_borrow.right_child_count + 1;
    }

    {
        let l_borrow = l.borrow();
        let left_depth = l_borrow.left_child_node.as_ref().map_or(0, |n| n.borrow().depth + 1);
        let right_depth = l_borrow.right_child_node.as_ref().map_or(0, |n| n.borrow().depth + 1);
        l.borrow_mut().depth = left_depth.max(right_depth);
    }

    l
}
