pub fn bostree_insert(&mut self, key: String, data: Option<String>) -> Rc<RefCell<BOSNode>> {
    // Find insertion position
    let mut parent_node: Option<Rc<RefCell<BOSNode>>> = None;
    let mut current = self.root_node.clone();

    while let Some(node) = current {
        parent_node = Some(node.clone());
        let cmp = (self.cmp_function)(&key, &node.borrow().key);
        let mut node_borrow = node.borrow_mut();
        if cmp < 0 {
            node_borrow.left_child_count += 1;
            current = node_borrow.left_child_node.clone();
        } else {
            node_borrow.right_child_count += 1;
            current = node_borrow.right_child_node.clone();
        }
    }

    // Create new node
    let new_node = Rc::new(RefCell::new(BOSNode {
        left_child_count: 0,
        right_child_count: 0,
        depth: 0,
        left_child_node: None,
        right_child_node: None,
        parent_node: parent_node.as_ref().map(|p| Rc::downgrade(p)),
        key,
        data,
        weak_ref_count: 1,
        weak_ref_node_valid: 1,
    }));

    // Insert the node
    match &parent_node {
        None => {
            self.root_node = Some(new_node.clone());
            return new_node;
        }
        Some(parent) => {
            let cmp = (self.cmp_function)(&new_node.borrow().key, &parent.borrow().key);
            let mut parent_borrow = parent.borrow_mut();
            if cmp < 0 {
                parent_borrow.left_child_node = Some(new_node.clone());
            } else {
                parent_borrow.right_child_node = Some(new_node.clone());
            }
        }
    }

    // Check if depth changed (only if this is the first child of the parent)
    let parent = parent_node.unwrap();
    let has_left = parent.borrow().left_child_node.is_some();
    let has_right = parent.borrow().right_child_node.is_some();

    if has_left != has_right {
        // Depth changed, need to rebalance
        parent.borrow_mut().depth += 1;

        let mut current = parent.clone();
        while let Some(parent_weak) = current.borrow().parent_node.clone() {
            let parent_node_rc = parent_weak.upgrade().unwrap();

            let new_left_depth = parent_node_rc.borrow().left_child_node.as_ref().map_or(0, |l| l.borrow().depth + 1);
            let new_right_depth = parent_node_rc.borrow().right_child_node.as_ref().map_or(0, |r| r.borrow().depth + 1);
            let max_depth = imax(new_left_depth, new_right_depth);

            let depth_changed = max_depth != parent_node_rc.borrow().depth;
            parent_node_rc.borrow_mut().depth = max_depth;

            if !depth_changed {
                break;
            }

            // Check AVL balance
            let balance = new_right_depth as i32 - new_left_depth as i32;

            if balance < -1 {
                // Left is deeper, rotate right
                let left_child = parent_node_rc.borrow().left_child_node.clone().unwrap();
                if bostree_balance(&left_child) > 0 {
                    bostree_rotate_left(self, &left_child);
                }
                current = bostree_rotate_right(self, &parent_node_rc);
            } else if balance > 1 {
                // Right is deeper, rotate left
                let right_child = parent_node_rc.borrow().right_child_node.clone().unwrap();
                if bostree_balance(&right_child) < 0 {
                    bostree_rotate_right(self, &right_child);
                }
                current = bostree_rotate_left(self, &parent_node_rc);
            } else {
                current = parent_node_rc;
            }
        }
    }

    new_node
}
