use std::cell::RefCell;
use std::rc::{Rc, Weak};

#[derive(Debug)]
pub struct BOSTree {
    pub root_node: Option<Rc<RefCell<BOSNode>>>,
    pub cmp_function: BOSTreeCmpFunction,
    pub free_function: Option<BOSTreeFreeFunction>,
}

#[derive(Debug)]
pub struct BOSNode {
    pub left_child_count: u32,
    pub right_child_count: u32,
    pub depth: u32,
    pub left_child_node: Option<Rc<RefCell<BOSNode>>>,
    pub right_child_node: Option<Rc<RefCell<BOSNode>>>,
    pub parent_node: Option<Weak<RefCell<BOSNode>>>,
    pub key: String,
    pub data: Option<String>,
    pub weak_ref_count: u8,
    pub weak_ref_node_valid: u8,
}

pub type BOSTreeCmpFunction = fn(&str, &str) -> i32;
pub type BOSTreeFreeFunction = fn(&Rc<RefCell<BOSNode>>);

// Helper functions
fn imax(i1: u32, i2: u32) -> u32 {
    std::cmp::max(i1, i2)
}

fn bostree_balance(node: &Rc<RefCell<BOSNode>>) -> i32 {
    let n = node.borrow();
    let left_depth = match &n.left_child_node {
        Some(l) => l.borrow().depth as i32 + 1,
        None => 0,
    };
    let right_depth = match &n.right_child_node {
        Some(r) => r.borrow().depth as i32 + 1,
        None => 0,
    };
    right_depth - left_depth
}

fn bostree_rotate_right(tree: &mut BOSTree, P: &Rc<RefCell<BOSNode>>) -> Rc<RefCell<BOSNode>> {
    let L = P.borrow().left_child_node.clone().unwrap();
    let P_parent_weak = P.borrow().parent_node.clone();
    let L_right = L.borrow().right_child_node.clone();
    let L_right_count = L.borrow().right_child_count;

    // Update P's parent's child pointer to L
    match &P_parent_weak {
        Some(parent_weak) => {
            let parent = parent_weak.upgrade().unwrap();
            let is_left = parent.borrow().left_child_node.as_ref().map_or(false, |l| Rc::ptr_eq(l, P));
            if is_left {
                parent.borrow_mut().left_child_node = Some(L.clone());
            } else {
                parent.borrow_mut().right_child_node = Some(L.clone());
            }
        }
        None => {
            tree.root_node = Some(L.clone());
        }
    }

    // Set L's parent to P's old parent
    L.borrow_mut().parent_node = P_parent_weak;

    // Set P's left child to L's right child, update count
    {
        let mut p_mut = P.borrow_mut();
        p_mut.left_child_node = L_right.clone();
        p_mut.left_child_count = L_right_count;
    }

    // Set L's right child's parent to P (if it exists)
    if let Some(ref lr) = L_right {
        lr.borrow_mut().parent_node = Some(Rc::downgrade(P));
    }

    // Update P's depth
    {
        let p_borrow = P.borrow();
        let p_left_depth = p_borrow.left_child_node.as_ref().map_or(0, |l| l.borrow().depth + 1);
        let p_right_depth = p_borrow.right_child_node.as_ref().map_or(0, |r| r.borrow().depth + 1);
        P.borrow_mut().depth = imax(p_left_depth, p_right_depth);
    }

    // Set P's parent to L
    P.borrow_mut().parent_node = Some(Rc::downgrade(&L));

    // Set L's right child to P
    L.borrow_mut().right_child_node = Some(P.clone());

    // Update L's right_child_count
    {
        let p_borrow = P.borrow();
        L.borrow_mut().right_child_count = p_borrow.left_child_count + p_borrow.right_child_count + 1;
    }

    // Update L's depth
    {
        let l_borrow = L.borrow();
        let l_left_depth = l_borrow.left_child_node.as_ref().map_or(0, |l| l.borrow().depth + 1);
        let l_right_depth = l_borrow.right_child_node.as_ref().map_or(0, |r| r.borrow().depth + 1);
        L.borrow_mut().depth = imax(l_left_depth, l_right_depth);
    }

    L
}

