    pub fn bostree_new(cmp_function: BOSTreeCmpFunction, free_function: Option<BOSTreeFreeFunction>) -> Self {
        BOSTree {
            root_node: None,
            cmp_function,
            free_function,
        }
    }

    pub fn bostree_node_count(&self) -> u32 {
        match &self.root_node {
            Some(root) => {
                let root_borrow = root.borrow();
                root_borrow.left_child_count + root_borrow.right_child_count + 1
            }
            None => 0,
        }
    }

    pub fn bostree_insert(&mut self, key: String, data: Option<String>) -> Rc<RefCell<BOSNode>> {
        let mut parent_node: Option<Rc<RefCell<BOSNode>>> = None;
        let mut current_opt = self.root_node.clone();

        while let Some(current) = current_opt {
            let cmp = (self.cmp_function)(&key, &current.borrow().key);
            parent_node = Some(current.clone());
            let mut current_borrow = current.borrow_mut();
            if cmp < 0 {
                current_borrow.left_child_count += 1;
                current_opt = current_borrow.left_child_node.clone();
            } else {
                current_borrow.right_child_count += 1;
                current_opt = current_borrow.right_child_node.clone();
            }
        }

        let new_node = Rc::new(RefCell::new(BOSNode {
            left_child_count: 0,
            right_child_count: 0,
            depth: 0,
            left_child_node: None,
            right_child_node: None,
            parent_node: parent_node.as_ref().map(|p| Rc::downgrade(p)),
            key,
            data,
            weak_ref_count: 1,
            weak_ref_node_valid: 1,
        }));

        match &parent_node {
            None => {
                self.root_node = Some(new_node.clone());
                return new_node;
            }
            Some(parent) => {
                let cmp = (self.cmp_function)(&new_node.borrow().key, &parent.borrow().key);
                let mut parent_borrow = parent.borrow_mut();
                if cmp < 0 {
                    parent_borrow.left_child_node = Some(new_node.clone());
                } else {
                    parent_borrow.right_child_node = Some(new_node.clone());
                }
            }
        }

        let parent = parent_node.unwrap();

        let has_left = parent.borrow().left_child_node.is_some();
        let has_right = parent.borrow().right_child_node.is_some();

        if has_left != has_right {
            parent.borrow_mut().depth += 1;

            let mut current = parent.clone();
            while current.borrow().parent_node.is_some() {
                let parent_weak = current.borrow().parent_node.clone().unwrap();
                let parent_node_rc = parent_weak.upgrade().unwrap();

                let new_left_depth = parent_node_rc.borrow().left_child_node.as_ref().map_or(0, |l| l.borrow().depth + 1);
                let new_right_depth = parent_node_rc.borrow().right_child_node.as_ref().map_or(0, |r| r.borrow().depth + 1);
                let max_depth = imax(new_left_depth, new_right_depth);

                let depth_changed = max_depth != parent_node_rc.borrow().depth;
                parent_node_rc.borrow_mut().depth = max_depth;

                if !depth_changed {
                    break;
                }

                let balance = new_right_depth as i32 - new_left_depth as i32;

                if balance < -1 {
                    let left_child = parent_node_rc.borrow().left_child_node.clone().unwrap();
                    if bostree_balance(&left_child) > 0 {
                        bostree_rotate_left(self, &left_child);
                    }
                    current = bostree_rotate_right(self, &parent_node_rc);
                } else if balance > 1 {
                    let right_child = parent_node_rc.borrow().right_child_node.clone().unwrap();
                    if bostree_balance(&right_child) < 0 {
                        bostree_rotate_right(self, &right_child);
                    }
                    current = bostree_rotate_left(self, &parent_node_rc);
                } else {
                    current = parent_node_rc;
                }
            }
        }

        new_node
    }

    pub fn bostree_remove(&mut self, node: &Rc<RefCell<BOSNode>>) {
        let mut bubble_up: Option<Rc<RefCell<BOSNode>>> = None;

        let has_left = node.borrow().left_child_node.is_some();
        let has_right = node.borrow().right_child_node.is_some();

        if has_left && has_right {
            let left_depth = node.borrow().left_child_node.as_ref().map_or(0, |l| l.borrow().depth);
            let right_depth = node.borrow().right_child_node.as_ref().map_or(0, |r| r.borrow().depth);

            let candidate: Rc<RefCell<BOSNode>>;
            let lost_child: Option<Rc<RefCell<BOSNode>>>;
            let bubble_start: Rc<RefCell<BOSNode>>;

            if left_depth >= right_depth {
                node.borrow_mut().left_child_count -= 1;
                let mut c = node.borrow().left_child_node.clone().unwrap();
                while c.borrow().right_child_node.is_some() {
                    c.borrow_mut().right_child_count -= 1;
                    let next = c.borrow().right_child_node.clone().unwrap();
                    c = next;
                }
                candidate = c;
                lost_child = candidate.borrow().left_child_node.clone();
                bubble_start = candidate.borrow().parent_node.clone().unwrap().upgrade().unwrap();
            } else {
                node.borrow_mut().right_child_count -= 1;
                let mut c = node.borrow().right_child_node.clone().unwrap();
                while c.borrow().left_child_node.is_some() {
                    c.borrow_mut().left_child_count -= 1;
                    let next = c.borrow().left_child_node.clone().unwrap();
                    c = next;
                }
                candidate = c;
                lost_child = candidate.borrow().right_child_node.clone();
                bubble_start = candidate.borrow().parent_node.clone().unwrap().upgrade().unwrap();
            }

            // Detach candidate from its parent
            {
                let mut bs_borrow = bubble_start.borrow_mut();
                let is_left = bs_borrow.left_child_node.as_ref().map_or(false, |lc| Rc::ptr_eq(lc, &candidate));
                if is_left {
                    bs_borrow.left_child_node = lost_child.clone();
                } else {
                    bs_borrow.right_child_node = lost_child.clone();
                }
            }
            if let Some(ref lc) = lost_child {
                lc.borrow_mut().parent_node = Some(Rc::downgrade(&bubble_start));
            }

            // Place candidate where node was
            let node_parent_weak = node.borrow().parent_node.clone();
            let node_left = node.borrow().left_child_node.clone();
            let node_left_count = node.borrow().left_child_count;
            let node_right = node.borrow().right_child_node.clone();
            let node_right_count = node.borrow().right_child_count;

            match &node_parent_weak {
                Some(parent_weak) => {
                    let parent = parent_weak.upgrade().unwrap();
                    let is_left = parent.borrow().left_child_node.as_ref().map_or(false, |lc| Rc::ptr_eq(lc, node));
                    if is_left {
                        parent.borrow_mut().left_child_node = Some(candidate.clone());
                    } else {
                        parent.borrow_mut().right_child_node = Some(candidate.clone());
                    }
                }
                None => {
                    self.root_node = Some(candidate.clone());
                }
            }

            candidate.borrow_mut().parent_node = node_parent_weak;

            // Skip setting candidate's children if candidate is one of node's children
            // (candidate was the immediate left or right child)
            let candidate_is_left = node_left.as_ref().map_or(false, |nl| Rc::ptr_eq(nl, &candidate));
            let candidate_is_right = node_right.as_ref().map_or(false, |nr| Rc::ptr_eq(nr, &candidate));

            if !candidate_is_left {
                candidate.borrow_mut().left_child_node = node_left.clone();
                candidate.borrow_mut().left_child_count = node_left_count;
                if let Some(ref nl) = node_left {
                    nl.borrow_mut().parent_node = Some(Rc::downgrade(&candidate));
                }
            }
            if !candidate_is_right {
                candidate.borrow_mut().right_child_node = node_right.clone();
                candidate.borrow_mut().right_child_count = node_right_count;
                if let Some(ref nr) = node_right {
                    nr.borrow_mut().parent_node = Some(Rc::downgrade(&candidate));
                }
            }

            // Rebalance from bubble_start up to candidate
            let need_rebalance = !Rc::ptr_eq(&bubble_start, node);
            if need_rebalance {
                let mut bs = bubble_start.clone();
                while !Rc::ptr_eq(&bs, &candidate) {
                    let bs_left_depth = bs.borrow().left_child_node.as_ref().map_or(0, |l| l.borrow().depth + 1);
                    let bs_right_depth = bs.borrow().right_child_node.as_ref().map_or(0, |r| r.borrow().depth + 1);
                    bs.borrow_mut().depth = imax(bs_left_depth, bs_right_depth);

                    let balance = bs_right_depth as i32 - bs_left_depth as i32;
                    if balance > 1 {
                        let right_child = bs.borrow().right_child_node.clone().unwrap();
                        if bostree_balance(&right_child) < 0 {
                            bostree_rotate_right(self, &right_child);
                        }
                        bs = bostree_rotate_left(self, &bs);
                    } else if balance < -1 {
                        let left_child = bs.borrow().left_child_node.clone().unwrap();
                        if bostree_balance(&left_child) > 0 {
                            bostree_rotate_left(self, &left_child);
                        }
                        bs = bostree_rotate_right(self, &bs);
                    }

                    let bs_parent = bs.borrow().parent_node.clone();
                    match bs_parent {
                        Some(parent_weak) => bs = parent_weak.upgrade().unwrap(),
                        None => break,
                    }
                }
            }

            // Fixup candidate depth
            {
                let c_left_depth = candidate.borrow().left_child_node.as_ref().map_or(0, |l| l.borrow().depth + 1);
                let c_right_depth = candidate.borrow().right_child_node.as_ref().map_or(0, |r| r.borrow().depth + 1);
                candidate.borrow_mut().depth = imax(c_left_depth, c_right_depth);
            }

            bubble_up = candidate.borrow().parent_node.clone().map(|w| w.upgrade().unwrap());

            if let Some(ref bu) = bubble_up {
                let is_left = bu.borrow().left_child_node.as_ref().map_or(false, |lc| Rc::ptr_eq(lc, &candidate));
                if is_left {
                    bu.borrow_mut().left_child_count -= 1;
                } else {
                    bu.borrow_mut().right_child_count -= 1;
                }
            }
        } else {
            // Node has at most one child
            let node_parent_weak = node.borrow().parent_node.clone();
            let node_left = node.borrow().left_child_node.clone();
            let node_right = node.borrow().right_child_node.clone();

            match &node_parent_weak {
                None => {
                    // Node is the root
                    if node_left.is_some() {
                        self.root_node = node_left.clone();
                        if let Some(ref nl) = node_left {
                            nl.borrow_mut().parent_node = None;
                        }
                    } else {
                        self.root_node = node_right.clone();
                        if let Some(ref nr) = node_right {
                            nr.borrow_mut().parent_node = None;
                        }
                    }
                    bubble_up = None;
                }
                Some(parent_weak) => {
                    let parent = parent_weak.upgrade().unwrap();
                    let candidate: Option<Rc<RefCell<BOSNode>>>;
                    let candidate_count: u32;

                    if node_left.is_some() {
                        candidate = node_left.clone();
                        candidate_count = node.borrow().left_child_count;
                    } else {
                        candidate = node_right.clone();
                        candidate_count = node.borrow().right_child_count;
                    }

                    let is_left = parent.borrow().left_child_node.as_ref().map_or(false, |lc| Rc::ptr_eq(lc, node));
                    if is_left {
                        parent.borrow_mut().left_child_node = candidate.clone();
                        parent.borrow_mut().left_child_count = candidate_count;
                    } else {
                        parent.borrow_mut().right_child_node = candidate.clone();
                        parent.borrow_mut().right_child_count = candidate_count;
                    }

                    if let Some(ref c) = candidate {
                        c.borrow_mut().parent_node = Some(Rc::downgrade(&parent));
                    }

                    bubble_up = Some(parent);
                }
            }
        }

        // Rebalance up to the root
        let mut bubbling_finished = false;
        let mut current_bubble = bubble_up;

        while let Some(bu) = current_bubble {
            if !bubbling_finished {
                let left_depth = bu.borrow().left_child_node.as_ref().map_or(0, |l| l.borrow().depth + 1);
                let right_depth = bu.borrow().right_child_node.as_ref().map_or(0, |r| r.borrow().depth + 1);
                let new_depth = imax(left_depth, right_depth);
                let depth_changed = new_depth != bu.borrow().depth;
                bu.borrow_mut().depth = new_depth;

                let balance = right_depth as i32 - left_depth as i32;

                if balance < -1 {
                    let left_child = bu.borrow().left_child_node.clone().unwrap();
                    if bostree_balance(&left_child) > 0 {
                        bostree_rotate_left(self, &left_child);
                    }
                    current_bubble = Some(bostree_rotate_right(self, &bu));
                } else if balance > 1 {
                    let right_child = bu.borrow().right_child_node.clone().unwrap();
                    if bostree_balance(&right_child) < 0 {
                        bostree_rotate_right(self, &right_child);
                    }
                    current_bubble = Some(bostree_rotate_left(self, &bu));
                } else {
                    if !depth_changed {
                        bubbling_finished = true;
                    }
                    current_bubble = Some(bu);
                }
            }

            // Decrement parent's child count
            let bu_parent_weak = current_bubble.as_ref().unwrap().borrow().parent_node.clone();
            if let Some(parent_weak) = bu_parent_weak {
                let parent = parent_weak.upgrade().unwrap();
                let bu_rc = current_bubble.as_ref().unwrap();
                let is_left = parent.borrow().left_child_node.as_ref().map_or(false, |lc| Rc::ptr_eq(lc, bu_rc));
                if is_left {
                    parent.borrow_mut().left_child_count -= 1;
                } else {
                    parent.borrow_mut().right_child_count -= 1;
                }
                current_bubble = Some(parent);
            } else {
                current_bubble = None;
            }
        }

        node.borrow_mut().weak_ref_node_valid = 0;
        self.bostree_node_weak_unref(node);
    }

    pub fn bostree_node_weak_unref(&mut self, node: &Rc<RefCell<BOSNode>>) -> Option<Rc<RefCell<BOSNode>>> {
        node.borrow_mut().weak_ref_count -= 1;
        let weak_ref_count = node.borrow().weak_ref_count;
        let weak_ref_node_valid = node.borrow().weak_ref_node_valid;

        if weak_ref_count == 0 {
            if let Some(free_fn) = self.free_function {
                free_fn(node);
            }
            None
        } else if weak_ref_node_valid != 0 {
            Some(node.clone())
        } else {
            None
        }
    }

    pub fn bostree_lookup(&self, key: &str) -> Option<Rc<RefCell<BOSNode>>> {
        let mut current_opt = self.root_node.clone();
        while let Some(current) = current_opt {
            let cmp = (self.cmp_function)(key, &current.borrow().key);
            if cmp == 0 {
                return Some(current);
            } else if cmp < 0 {
                current_opt = current.borrow().left_child_node.clone();
            } else {
                current_opt = current.borrow().right_child_node.clone();
            }
        }
        None
    }

    pub fn bostree_select(&self, index: u32) -> Option<Rc<RefCell<BOSNode>>> {
        let mut current_opt = self.root_node.clone();
        let mut idx = index;
        while let Some(current) = current_opt {
            let left_count = current.borrow().left_child_count;
            if left_count <= idx {
                idx -= left_count;
                if idx == 0 {
                    return Some(current);
                }
                idx -= 1;
                current_opt = current.borrow().right_child_node.clone();
            } else {
                current_opt = current.borrow().left_child_node.clone();
            }
        }
        None
    }

    #[cfg(debug_assertions)]
    pub fn bostree_print(&self) {
        if self.root_node.is_none() {
            return;
        }
        println!("digraph {{\n  ordering = out;");
        fn print_helper(node: &Rc<RefCell<BOSNode>>) {
            let n = node.borrow();
            println!("  {} [label=\\N ({},{},{})];", n.key, n.left_child_count, n.right_child_count, n.depth);
            if let Some(ref parent_weak) = n.parent_node {
                if let Some(parent) = parent_weak.upgrade() {
                    println!("  {} -> {} [color=green];", n.key, parent.borrow().key);
                }
            }
            if let Some(ref left) = n.left_child_node {
                println!("  {} -> {}", n.key, left.borrow().key);
                print_helper(left);
            }
            if let Some(ref right) = n.right_child_node {
                println!("  {} -> {}", n.key, right.borrow().key);
                print_helper(right);
            }
        }
        print_helper(self.root_node.as_ref().unwrap());
        println!("}}");
    }
}

pub fn bostree_node_weak_ref(node: &Rc<RefCell<BOSNode>>) -> Rc<RefCell<BOSNode>> {
    assert!(node.borrow().weak_ref_count < 127);
    assert!(node.borrow().weak_ref_count > 0);
    node.borrow_mut().weak_ref_count += 1;
    node.clone()
}

pub fn bostree_next_node(node: &Rc<RefCell<BOSNode>>) -> Option<Rc<RefCell<BOSNode>>> {
    let right = node.borrow().right_child_node.clone();
    if right.is_some() {
        let mut n = right.unwrap();
        while n.borrow().left_child_node.is_some() {
            let next = n.borrow().left_child_node.clone().unwrap();
            n = next;
        }
        return Some(n);
    }

    let parent_weak = node.borrow().parent_node.clone();
    if let Some(parent_weak) = parent_weak {
        let mut n = node.clone();
        while let Some(pw) = n.borrow().parent_node.clone() {
            let parent = pw.upgrade().unwrap();
            let is_right = parent.borrow().right_child_node.as_ref().map_or(false, |rc| Rc::ptr_eq(rc, &n));
            if is_right {
                n = parent;
            } else {
                return Some(parent);
            }
        }
    }
    None
}

pub fn bostree_previous_node(node: &Rc<RefCell<BOSNode>>) -> Option<Rc<RefCell<BOSNode>>> {
    let left = node.borrow().left_child_node.clone();
    if left.is_some() {
        let mut n = left.unwrap();
        while n.borrow().right_child_node.is_some() {
            let next = n.borrow().right_child_node.clone().unwrap();
            n = next;
        }
        return Some(n);
    }

    let parent_weak = node.borrow().parent_node.clone();
    if let Some(parent_weak) = parent_weak {
        let mut n = node.clone();
        while let Some(pw) = n.borrow().parent_node.clone() {
            let parent = pw.upgrade().unwrap();
            let is_left = parent.borrow().left_child_node.as_ref().map_or(false, |lc| Rc::ptr_eq(lc, &n));
            if is_left {
                n = parent;
            } else {
                return Some(parent);
            }
        }
    }
    None
}

pub fn bostree_rank(node: &Rc<RefCell<BOSNode>>) -> u32 {
    let mut counter = node.borrow().left_child_count;
    let mut current_weak = node.borrow().parent_node.clone();
    while let Some(pw) = current_weak {
        let parent = pw.upgrade().unwrap();
        let is_right = parent.borrow().right_child_node.as_ref().map_or(false, |rc| Rc::ptr_eq(rc, node));
        if is_right {
            counter += 1 + parent.borrow().left_child_count;
        }
        current_weak = parent.borrow().parent_node.clone();
    }
    counter
}
