            let bu_parent_weak = bu_rc.borrow().parent_node.clone();
            if let Some(parent_weak) = bu_parent_weak {
                let parent = parent_weak.upgrade().unwrap();
                let is_left = parent.borrow().left_child_node.as_ref().map_or(false, |lc| Rc::ptr_eq(lc, &bu_rc));
                if is_left {
                    parent.borrow_mut().left_child_count -= 1;
                } else {
                    parent.borrow_mut().right_child_count -= 1;
                }
