            }
        }

        node.borrow_mut().weak_ref_node_valid = 0;
        self.bostree_node_weak_unref(node);
    }

    pub fn bostree_node_weak_unref(&mut self, node: &Rc<RefCell<BOSNode>>) -> Option<Rc<RefCell<BOSNode>>> {
        node.borrow_mut().weak_ref_count -= 1;
        let weak_ref_count = node.borrow().weak_ref_count;
        let weak_ref_node_valid = node.borrow().weak_ref_node_valid;

        if weak_ref_count == 0 {
            if let Some(free_fn) = self.free_function {
                free_fn(node);
            }
            None
        } else if weak_ref_node_valid != 0 {
            Some(node.clone())
        } else {
            None
        }
    }

    pub fn bostree_lookup(&self, key: &str) -> Option<Rc<RefCell<BOSNode>>> {
        let mut current_opt = self.root_node.clone();
        while let Some(current) = current_opt {
            let cmp = (self.cmp_function)(key, &current.borrow().key);
            if cmp == 0 {
                return Some(current);
            } else if cmp < 0 {
                current_opt = current.borrow().left_child_node.clone();
            } else {
                current_opt = current.borrow().right_child_node.clone();
            }
        }
        None
    }

    pub fn bostree_select(&self, index: u32) -> Option<Rc<RefCell<BOSNode>>> {
        let mut current_opt = self.root_node.clone();
        let mut idx = index;
        while let Some(current) = current_opt {
            let left_count = current.borrow().left_child_count;
            if left_count <= idx {
                idx -= left_count;
                if idx == 0 {
                    return Some(current);
                }
                idx -= 1;
                current_opt = current.borrow().right_child_node.clone();
            } else {
                current_opt = current.borrow().left_child_node.clone();
            }
        }
        None
    }

