        }
        println!("digraph {{\n  ordering = out;");
        fn print_helper(node: &Rc<RefCell<BOSNode>>) {
            let n = node.borrow();
            println!("  {} [label=\\N ({},{},{})];", n.key, n.left_child_count, n.right_child_count, n.depth);
            if let Some(ref parent_weak) = n.parent_node {
                if let Some(parent) = parent_weak.upgrade() {
                    println!("  {} -> {} [color=green];", n.key, parent.borrow().key);
                }
            }
            if let Some(ref left) = n.left_child_node {
                println!("  {} -> {}", n.key, left.borrow().key);
                print_helper(left);
            }
            if let Some(ref right) = n.right_child_node {
                println!("  {} -> {}", n.key, right.borrow().key);
                print_helper(right);
            }
        }
        print_helper(self.root_node.as_ref().unwrap());
        println!("}}");
    }
}

pub fn bostree_node_weak_ref(node: &Rc<RefCell<BOSNode>>) -> Rc<RefCell<BOSNode>> {
    assert!(node.borrow().weak_ref_count < 127);
    assert!(node.borrow().weak_ref_count > 0);
    node.borrow_mut().weak_ref_count += 1;
    node.clone()
}

pub fn bostree_next_node(node: &Rc<RefCell<BOSNode>>) -> Option<Rc<RefCell<BOSNode>>> {
    if node.borrow().right_child_node.is_some() {
        let mut n = node.borrow().right_child_node.clone().unwrap();
        while n.borrow().left_child_node.is_some() {
            let next = n.borrow().left_child_node.clone().unwrap();
            n = next;
        }
        return Some(n);
    }

    let mut n = node.clone();
    loop {
        let parent_weak = n.borrow().parent_node.clone();
        match parent_weak {
            None => return None,
            Some(pw) => {
                let parent = pw.upgrade().unwrap();
                let is_right = parent.borrow().right_child_node.as_ref().map_or(false, |rc| Rc::ptr_eq(rc, &n));
                if is_right {
                    n = parent;
                } else {
                    return Some(parent);
                }
            }
        }
    }
}

pub fn bostree_previous_node(node: &Rc<RefCell<BOSNode>>) -> Option<Rc<RefCell<BOSNode>>> {
    if node.borrow().left_child_node.is_some() {
        let mut n = node.borrow().left_child_node.clone().unwrap();
        while n.borrow().right_child_node.is_some() {
            let next = n.borrow().right_child_node.clone().unwrap();
            n = next;
        }
        return Some(n);
    }

    let mut n = node.clone();
    loop {
        let parent_weak = n.borrow().parent_node.clone();
        match parent_weak {
            None => return None,
            Some(pw) => {
                let parent = pw.upgrade().unwrap();
                let is_left = parent.borrow().left_child_node.as_ref().map_or(false, |lc| Rc::ptr_eq(lc, &n));
                if is_left {
                    n = parent;
                } else {
                    return Some(parent);
                }
            }
        }
    }
}

pub fn bostree_rank(node: &Rc<RefCell<BOSNode>>) -> u32 {
    let mut counter = node.borrow().left_child_count;
    let mut current = node.clone();
    loop {
        let parent_weak = current.borrow().parent_node.clone();
        match parent_weak {
            None => return counter,
            Some(pw) => {
                let parent = pw.upgrade().unwrap();
                let is_right = parent.borrow().right_child_node.as_ref().map_or(false, |rc| Rc::ptr_eq(rc, &current));
                if is_right {
                    counter += 1 + parent.borrow().left_child_count;
                }
                current = parent;
            }
        }
    }
}
